class Solution {
    public List<Integer> maxScoreIndices(int[] nums) {
        int n = nums.length;
        int[] prefixSum = new int[n + 1];
        for (int i = 0; i < n; i++) {
            prefixSum[i + 1] = prefixSum[i] + (nums[i] == 0 ? 1 : 0);
        }
        int maxScore = 0;
        List<Integer> result = new ArrayList<>();
        for (int i = 0; i <= n; i++) {
            int score = prefixSum[i] + (n - i - 1) - prefixSum[i];
            if (score > maxScore) {
                maxScore = score;
                result.clear();
                result.add(i);
            } else if (score == maxScore) {
                result.add(i);
            }
        }
        return result;
    }
}
